import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Поиск безопасных модификаций","description":"Гайд о том, как найти моды для Fabric, используя надежные источники.","frontmatter":{"title":"Поиск безопасных модификаций","description":"Гайд о том, как найти моды для Fabric, используя надежные источники.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ru_ru/players/finding-mods.md","filePath":"translated/ru_ru/players/finding-mods.md","lastUpdated":1770561656000}`);var a={name:`ru_ru/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Поиск безопасных модификаций <a class="header-anchor" href="#h1" aria-label="Permalink to “Поиск безопасных модификаций”">​</a></h1><p>Во-первых, доверие субъективно, и вы всегда должны руководствоваться своим собственным мнением при загрузке модов. Тем не менее есть некоторые вещи, которые вы можете сделать, чтобы найти заслуживающие доверия моды.</p><h2 id="trustworthy-source" tabindex="-1">1. Используйте безопасные источники <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. Используйте безопасные источники”">​</a></h2><p>Большинство авторов публикуют свои моды на <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> и <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Эти сайты проверяют, являются ли моды тем, за что они себя выдают, и что они не содержат вредоносного кода. Вы также можете сообщить о вредоносных модах на этих сайтах, и они примут меры относительно быстро.</p><h2 id="with-others" tabindex="-1">2. Посоветуйтесь с другими! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Посоветуйтесь с другими!”">​</a></h2><p>Если вы загружаете мод из источника, который не безопасен, вам следует посоветоваться с другими людьми, чтобы узнать, загружали ли они мод ранее из того места, откуда загружаете вы, и не возникали ли у них какие-либо проблемы с ним.</p><p>Если у вас есть сомнения, вы можете спросить мнения людей в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord Fabric</a> в канале <code>#player-support</code>.</p><h2 id="avoid-malware" tabindex="-1">3. Избегайте вредоносных сайтов! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Избегайте вредоносных сайтов!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Вредоносные сайты могут быть очевидны не для всех. Если вы не уверены, вам следует спросить мнения других или вообще избегать других сайтов и полагаться только на надежные источники, такие как Modrinth и CurseForge.</p></div><p>Есть много сайтов, которые утверждают, что у них есть моды для Minecraft, но на самом деле это просто вредоносные сайты. Вам следует избегать этих сайтов любой ценой.</p><p>Вы можете использовать антивирусы и сайты, такие как <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> или <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> для проверки загруженных модов. Однако не стоит полностью полагаться на эти методы, поскольку иногда они могут быть некорректными.</p><p>Опять же, если у вас есть сомнения, вы можете спросить мнения людей <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord Fabric</a> в канале <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};